1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	};
10	
11	type Item = { type: string };
12	type QuoteStep = { op: "quote"; items: Item[] };
13	type Step = QuoteStep;
14	type Scenario = { customer: unknown; steps: Step[] };
15	type QuoteResult = { premium: number };
16	type StepResult = QuoteResult;
17	
18	const basePremiumForItem = (item: Item): number =>
19	  BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0;
20	
21	const totalBasePremium = (items: Item[]): number =>
22	  items.reduce((total, item) => total + basePremiumForItem(item), 0);
23	
24	const quote = (step: QuoteStep): QuoteResult => ({
25	  premium: totalBasePremium(step.items) + PROCESSING_FEE,
26	});
27	
28	export const processScenario = (input: Scenario): { results: StepResult[] } => ({
29	  results: input.steps.map(quote),
30	});
